from lxml import etree

def get_student_info(xml_data: str, username: str, password: str) -> Optional[Dict[str, str]]:
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    for student in root.findall('student'):
        uname_el = student.find('username')
        pass_el = student.find('password')
        if uname_el is not None and pass_el is not None:
            if uname_el.text == username and pass_el.text == password:
                info = {}
                for child in student:
                    if child.text is not None:
                        info[child.tag] = child.text
                return info
    return None

import re

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    # If subdomain is empty or invalid, return the domain itself with HTTPS
    if not subdomain_prefix or not is_valid_subdomain(subdomain_prefix):
        return f"https://{domain}"
    return f"https://{subdomain_prefix}.{domain}"

def is_valid_subdomain(subdomain: str) -> bool:
    # Allow only alphanumeric, hyphens, and dots; no consecutive dots; no leading/trailing dot or hyphen
    if not re.fullmatch(r'[a-zA-Z0-9.-]+', subdomain):
        return False
    if '..' in subdomain:
        return False
    if subdomain.startswith('.') or subdomain.endswith('.'):
        return False
    if subdomain.startswith('-') or subdomain.endswith('-'):
        return False
    return True

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    """
    Generate a URL for querying user info based on a given API URL and user ID.
    Returns None if the user ID is empty or invalid.
    """
    if not user_id:
        return None
    # Ensure exactly one slash between api_url and user_id
    if api_url.endswith('/'):
        return api_url + user_id
    else:
        return api_url + '/' + user_id

