import shlex

def executeCommand():
    # Read command from user input
    user_input = input("Enter command: ").strip()
    if not user_input:
        print("No command entered.")
        return

    # Split into command and arguments safely
    try:
        parts = shlex.split(user_input)
    except ValueError as e:
        print(f"Invalid input: {e}")
        return

    if not parts:
        print("Empty command.")
        return

    command = parts[0]
    args = parts[1:]

    # Whitelist of allowed commands (no arguments that could be dangerous)
    allowed_commands = {
        'ls', 'pwd', 'date', 'whoami', 'echo', 'cat', 'head', 'tail',
        'wc', 'sort', 'uniq', 'grep', 'find', 'xargs', 'cut', 'tr',
        'df', 'du', 'free', 'uptime', 'uname', 'id', 'printenv'
    }

    if command not in allowed_commands:
        print(f"Command '{command}' is not allowed.")
        return

    # Execute the command safely without shell
    try:
        result = subprocess.run([command] + args, capture_output=True, text=True, check=True)
        print(result.stdout)
    except subprocess.CalledProcessError as e:
        print(f"Command failed with exit code {e.returncode}: {e.stderr}")
    except FileNotFoundError:
        print(f"Command '{command}' not found.")
    except Exception as e:
        print(f"Error executing command: {e}")

