import json


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with json to token object.
    Check if the token is valid and return the data if it is valid.
    '''
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        token_bytes = base64.b64decode(token_str)
        token = json.loads(token_bytes)
        if isinstance(token, dict) and token.get('valid'):
            return token.get('data')
        return None
    except Exception:
        return None

